const rawNewsItems = $('Execute a SQL query').all().map((i) => i.json);
const rawSubscribers = $input.all().map((i) => i.json);

function normalizeText(value) {
  return String(value ?? '')
    .replace(/[\u200B-\u200D\uFEFF\u00A0]/g, '')
    .trim()
    .replace(/^[\s"'“”‘’]+|[\s"'“”‘’]+$/g, '');
}

function normalizeSourceKey(value) {
  return normalizeText(value).toLowerCase();
}

function dedupeNews(items) {
  const seen = new Set();
  const result = [];
  for (const row of items) {
    const key =
      normalizeText(row.url) ||
      normalizeText(row.discussion_link) ||
      `${normalizeText(row.title_cn)}|${normalizeText(row.created_at)}`;
    if (!key || seen.has(key)) continue;
    seen.add(key);
    result.push(row);
  }
  return result;
}

function dedupeSubscribers(items) {
  const map = new Map();
  for (const s of items) {
    if (!s || !s.email) continue;
    const k = normalizeText(s.email).toLowerCase();
    if (!map.has(k)) map.set(k, s);
  }
  return Array.from(map.values());
}

const newsItems = dedupeNews(rawNewsItems);
const subscribers = dedupeSubscribers(rawSubscribers);

if (!subscribers.length) {
  return [];
}

function parseSources(raw) {
  if (Array.isArray(raw)) {
    return raw.map((v) => normalizeText(v)).filter(Boolean);
  }

  if (typeof raw === 'string' && raw.trim()) {
    try {
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        return parsed.map((v) => normalizeText(v)).filter(Boolean);
      }
    } catch (e) {
      return raw.split(',').map((v) => normalizeText(v)).filter(Boolean);
    }
  }

  return [];
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function formatDate(date, timezone) {
  try {
    return new Intl.DateTimeFormat('zh-CN', {
      month: 'long',
      day: 'numeric',
      timeZone: timezone,
    }).format(new Date(date));
  } catch {
    return new Intl.DateTimeFormat('zh-CN', {
      month: 'long',
      day: 'numeric',
      timeZone: 'Asia/Shanghai',
    }).format(new Date(date));
  }
}

function formatTime(date, timezone) {
  try {
    return new Intl.DateTimeFormat('zh-CN', {
      hour: '2-digit',
      minute: '2-digit',
      hour12: false,
      timeZone: timezone,
    }).format(new Date(date));
  } catch {
    return '';
  }
}

function getRowSourceLabel(row) {
  return (
    normalizeText(row.source_type) ||
    normalizeText(row.source_name) ||
    'Other'
  );
}

function getRowSourceKey(row) {
  const byType = normalizeSourceKey(row.source_type);
  if (byType) return byType;

  const byName = normalizeSourceKey(row.source_name);
  if (byName) return byName;

  const byKey = normalizeSourceKey(row.source_key);
  if (byKey) return byKey;

  return 'other';
}

function isHackerNews(sourceKey, row) {
  return (
    sourceKey === 'hackernews' ||
    normalizeSourceKey(row.source_key) === 'hackernews_frontpage'
  );
}

function compareRows(a, b, sourceKey) {
  if (isHackerNews(sourceKey, a)) {
    const scoreDiff = (Number(b.points) || 0) - (Number(a.points) || 0);
    if (scoreDiff !== 0) return scoreDiff;
  }
  return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
}

function pickNewsForSubscriber(preferredSources) {
  const TOTAL_LIMIT = 18;
  const MIN_PER_SOURCE = 2; // if available
  const MAX_PER_SOURCE = 7;

  const preferredKeys = preferredSources
    .map((s) => normalizeSourceKey(s))
    .filter(Boolean);

  const sourceSet = preferredKeys.length ? new Set(preferredKeys) : null;

  const filtered = sourceSet
    ? newsItems.filter((n) => sourceSet.has(getRowSourceKey(n)))
    : newsItems.slice();

  if (!filtered.length) return [];

  const grouped = new Map();
  for (const row of filtered) {
    const sourceKey = getRowSourceKey(row);
    const sourceLabel = getRowSourceLabel(row);

    if (!grouped.has(sourceKey)) {
      grouped.set(sourceKey, { label: sourceLabel, rows: [] });
    }

    grouped.get(sourceKey).rows.push({
      ...row,
      __sourceKey: sourceKey,
      __sourceLabel: sourceLabel,
    });
  }

  const sourceOrder = preferredKeys.length
    ? preferredKeys.filter((k) => grouped.has(k))
    : Array.from(grouped.keys());

  if (!sourceOrder.length) return [];

  for (const sourceKey of sourceOrder) {
    grouped.get(sourceKey).rows.sort((a, b) => compareRows(a, b, sourceKey));
  }

  const picked = [];
  const nextIndex = new Map();
  const countBySource = new Map();

  for (const sourceKey of sourceOrder) {
    nextIndex.set(sourceKey, 0);
    countBySource.set(sourceKey, 0);
  }

  for (const sourceKey of sourceOrder) {
    if (picked.length >= TOTAL_LIMIT) break;

    const rows = grouped.get(sourceKey).rows;
    const take = Math.min(MIN_PER_SOURCE, rows.length, TOTAL_LIMIT - picked.length);

    for (let i = 0; i < take; i++) picked.push(rows[i]);

    nextIndex.set(sourceKey, take);
    countBySource.set(sourceKey, take);
  }

  while (picked.length < TOTAL_LIMIT) {
    let best = null;

    for (const sourceKey of sourceOrder) {
      const rows = grouped.get(sourceKey).rows;
      const idx = nextIndex.get(sourceKey) || 0;
      const count = countBySource.get(sourceKey) || 0;

      if (idx >= rows.length) continue;
      if (count >= MAX_PER_SOURCE) continue;

      const candidate = rows[idx];

      if (!best) {
        best = { sourceKey, row: candidate };
      } else {
        const t1 = new Date(candidate.created_at).getTime();
        const t2 = new Date(best.row.created_at).getTime();
        if (t1 > t2) best = { sourceKey, row: candidate };
      }
    }

    if (!best) break;

    picked.push(best.row);
    nextIndex.set(best.sourceKey, (nextIndex.get(best.sourceKey) || 0) + 1);
    countBySource.set(best.sourceKey, (countBySource.get(best.sourceKey) || 0) + 1);
  }

  picked.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
  return picked.slice(0, TOTAL_LIMIT);
}

function formatShortDateTime(dateStr, timezone) {
  try {
    const d = new Date(dateStr);
    const datePart = new Intl.DateTimeFormat('en-US', {
      month: 'numeric',
      day: 'numeric',
      timeZone: timezone,
    }).format(d);

    const timePart = new Intl.DateTimeFormat('zh-CN', {
      hour: '2-digit',
      minute: '2-digit',
      hour12: false,
      timeZone: timezone,
    }).format(d);

    return `${datePart} ${timePart}`;
  } catch {
    return '';
  }
}

function buildEmailBody(subscriber, pickedNews) {
  const timezone = subscriber.timezone || 'Asia/Shanghai';
  const rawName = normalizeText(subscriber.name);
  const isValidName = rawName && !/^\d+$/.test(rawName);

  const dateStr = formatDate(new Date(), timezone);

  let html = '';
  html += '<div style="font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; max-width: 600px; margin: 0 auto; color: #000000;">';

  html += '<div style="padding-bottom: 16px; border-bottom: 2px solid #000000; margin-bottom: 24px;">';
  html += '<h1 style="margin: 0; font-size: 24px; font-weight: 700; letter-spacing: -0.5px; color: #000000;">Tech Briefing</h1>';
  html += '<p style="margin: 4px 0 0 0; color: #000000; font-size: 14px; font-weight: 620;">' + escapeHtml(dateStr) + ' | ' + escapeHtml(timezone) + '</p>';

  if (isValidName) {
    html += '<p style="margin: 4px 0 0 0; color: #000000; font-size: 14px; font-weight: 620;">Hi, ' + escapeHtml(rawName) + '</p>';
  }

  html += '</div>';

  html += '<div>';
  if (!pickedNews.length) {
    html += '<div style="padding: 16px; border: 1px solid #dfe1e5; border-radius: 4px; background: #fafafa;">';
    html += '<p style="margin: 0; font-size: 14px; line-height: 1.6; font-weight: 650; color: #202124;">No items matched your selected sources in the last 24 hours.</p>';
    html += '</div>';
  } else {
    for (const news of pickedNews) {
      const sourceLabel = news.__sourceLabel || getRowSourceLabel(news);
      const sourceKey = news.__sourceKey || getRowSourceKey(news);
      const sentiment = (news.sentiment || 'Neutral').toString();
      const sentimentLabel = sentiment.charAt(0).toUpperCase() + sentiment.slice(1).toLowerCase();

      const sentimentColor =
        sentimentLabel === 'Positive' ? '#0d652d' :
        sentimentLabel === 'Negative' ? '#a50e0e' : '#444444';

      const metricLabel = sourceKey === 'hackernews'
        ? ((Number(news.points) || 0) + ' Points')
        : formatShortDateTime(news.created_at, timezone);

      html += '<div style="margin-bottom: 28px;">';

      html += '<div style="font-size: 12px; color: #444444; margin-bottom: 4px; font-weight: 650;">';
      html += '<span style="color: #000000;">' + escapeHtml(sourceLabel) + '</span>';
      html += '<span style="margin: 0 6px; color: #999;">&middot;</span>';
      html += '<span>' + escapeHtml(metricLabel) + '</span>';
      html += '<span style="margin: 0 6px; color: #999;">&middot;</span>';
      html += '<span style="color: ' + sentimentColor + ';">' + escapeHtml(sentimentLabel) + '</span>';
      html += '</div>';

      html += '<h3 style="margin: 0 0 6px 0; font-size: 18px; line-height: 1.4; font-weight: 650;">';
      html += '<a href="' + escapeHtml(news.discussion_link || news.url || '#') + '" style="text-decoration: none; color: #1a73e8;">' + escapeHtml(news.title_cn || 'Untitled News') + '</a>';
      html += '</h3>';

      html += '<p style="margin: 0; font-size: 14px; color: #202124; line-height: 1.6; font-weight: 650;">' + escapeHtml(news.summary || '暂无摘要') + '</p>';
      html += '</div>';
    }
  }
  html += '</div>';

  html += '<div style="padding-top: 30px; border-top: 1px solid #dfe1e5; text-align: center;">';
  html += '<div style="margin-bottom: 16px;">';
  html += '<a href="https://dashboard.trainingcqy.com" style="display: inline-block; width: 160px; background-color: #1a73e8; color: #ffffff; padding: 12px 0; text-align: center; border-radius: 4px; text-decoration: none; font-size: 14px; font-weight: 700;">View Dashboard</a>';
  html += '</div>';
  html += '<div style="margin-bottom: 24px;">';
  html += '<a href="https://agent.trainingcqy.com" style="display: inline-block; width: 160px; background-color: #1a73e8; color: #ffffff; padding: 12px 0; text-align: center; border-radius: 4px; text-decoration: none; font-size: 14px; font-weight: 700;">Ask Agent</a>';
  html += '</div>';
  html += '<p style="margin: 0; color: #70757a; font-size: 12px;">To unsubscribe, update your preference on the <a href="https://agent.trainingcqy.com/subscribe" style="color: #1a73e8; text-decoration: none;">subscription page</a>.</p>';
  html += '</div>';
  html += '</div>';

  return html;
}

const output = [];
for (const sub of subscribers) {
  if (!sub.email) continue;

  const preferredSources = parseSources(sub.source_preferences);
  const pickedNews = pickNewsForSubscriber(preferredSources);
  const timezone = sub.timezone || 'Asia/Shanghai';
  const subjectDate = formatDate(new Date(), timezone);

  output.push({
    json: {
      to_email: sub.email,
      subject: 'Tech Briefing | ' + subjectDate,
      email_body: buildEmailBody(sub, pickedNews),
    },
  });
}

return output;
